import axios from 'axios';

export const Feedback = () => {
    const [appFeedback, setAppFeedback] = useState("");



    return (
        <div className="user-feedback">
            <h1>Feedback Page</h1>
            <label for="feedback" id="feedback-prompt">Any questions, comments, or suggestions of the application.</label>
            <textarea id="feedback" name="feedback" cols="50" rows="13" placeholder="Questions, comments, or suggestions...">

            </textarea>
            <input type='submit' value="submit"/>
        </div>
    );
};
